%[text] # Comparison All
%[text] Direct comparison of static data for an arbitrary amount of cases.
clear; clc; close all hidden;
%%
%[text] ## Configuration
AXIS = 3; %[control:dropdown:7ac0]{"position":[8,9]}
BASE_FOLDER = "/Users/alexwang/Documents/MATLAB/Linear Traverse/Data"; %[control:filebrowser:1a7f]{"position":[15,70]}
OUT_FOLDER = "/Users/alexwang/Downloads"; %[control:filebrowser:2fa5]{"position":[14,41]}
MAX = 1; %[control:slider:32c3]{"position":[7,8]}
ERRORBAR = true; %[control:checkbox:3bbe]{"position":[12,16]}
CF_VOLTAGE = 4;
%%
FOLDERS = {
    '2025_07_25_Y0_STAT', ...
    '2025_07_25_Y11.25_STAT', ...
    '2025_07_24_Y22.5_STAT', ...
    '2025_07_24_Y33.75_STAT' ...
    '2025_07_24_Y45_STAT' ...
};

LABELS = containers.Map(FOLDERS, { ...
    'ψ = 0°', ...
    'ψ = 11.25°', ...
    'ψ = 22.5°', ...
    'ψ = 33.75°', ...
    'ψ = 45°' ...
});

% FOLDERS = {
%     '2025_07_24_Y90_STAT', ...
%     '2025_07_24_Y78.75_STAT', ...
%     '2025_07_24_Y67.5_STAT', ...
%     '2025_07_24_Y56.25_STAT' ...
%     '2025_07_24_Y45_STAT' ...
% };

% LABELS = containers.Map(FOLDERS, { ...
%     'ψ = 90°', ...
%     'ψ = 78.75°', ...
%     'ψ = 67.5°', ...
%     'ψ = 56.25°', ...
%     'ψ = 45°' ...
% });

colors = slanCM('GnBu', 2 + length(FOLDERS)); %[output:704af998]
%%
name = Config.NAMES(AXIS);
conv = dictionary(Config.NAMES, ["F_y" "F_x" "F_z" "M_y" "M_x" "M_z"]);
disp_name = conv(name);
colors = colors(3:end, :);

out_folder = fullfile(OUT_FOLDER, strjoin(["comparison", "stacked", disp_name], "-"));

if ~exist(out_folder, "dir")
    mkdir(out_folder);
end
%%
%[text] ## FT Comparison
%[text] Plot chosen axis versus distance.
if AXIS <= 3
    DENOMINATOR = Config.W * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Force, $\bar{" + disp_name + "}/W$"); %[output:0ca06341]
else
    DENOMINATOR = Config.W * Config.L * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Moment, $\bar{" + disp_name + "}/(Wl)$");
end

xlim([0 9]); %[output:0ca06341]
set(gcf, 'Position', [100 100 750 750]); %[output:0ca06341]

handles = gobjects(length(FOLDERS), 1);

for k = 1:length(FOLDERS)
    folder = FOLDERS{k};
    load(fullfile(BASE_FOLDER, folder, 'processed_data.mat'), 'results');
    SDS = results.(name).SD / (Config.L / 1000);
    static = table2array(results.(name)(:, 2:end)) / DENOMINATOR;

    if ERRORBAR == true
        % Plot results (error bars)
        h = errorbar(SDS, mean(static, 2), std(static, 0, 2), 'o--', 'Color', colors(k, :), 'MarkerFaceColor', colors(k, :), 'LineWidth', 1.5); %[output:0ca06341]
    else
        % Plot results (data)
        h = plot(SDS, static, "x", 'Color', colors(k, :), "MarkerSize", 8, "LineWidth", 1.5);
    end

    handles(k) = h(1);
end

legend(handles, values(LABELS, FOLDERS), 'Location', 'northeast'); %[output:0ca06341]

%% Save
exportgraphics(gca, fullfile(out_folder, "FT.svg"), 'ContentType', 'vector'); %[output:0ca06341]
savefig(gcf, fullfile(out_folder, "FT.fig"));
%%
%[text] ## Crazyflie Power
figure; %[output:13941458]
Process.format_plot("", "Separation, $\Delta z/l$", "Power, W"); %[output:13941458]

xlim([0 9]); %[output:13941458]
ylim([5 10]); %[output:13941458]
set(gcf, 'Position', [100 100 750 750]); %[output:13941458]

handles = gobjects(length(FOLDERS), 1);

for k = 1:length(FOLDERS)
    folder = FOLDERS{k};
    load(fullfile(BASE_FOLDER, folder, 'processed_data.mat'), 'results');
    SDS = results.(name).SD / (Config.L / 1000);
    current = table2array(results.Current(:, 2:end));
    power = current * CF_VOLTAGE;

    if ERRORBAR == true
        % Plot results (error bars)
        h = errorbar(SDS, mean(power, 2), std(power, 0, 2), 'o--', 'Color', colors(k, :), 'MarkerFaceColor', colors(k, :), 'LineWidth', 1.5); %[output:13941458]
    else
        % Plot results (data)
        h = plot(SDS, power, "x", 'Color', colors(k, :), "MarkerSize", 8, "LineWidth", 1.5);
    end

    handles(k) = h(1);
end

legend(handles, values(LABELS, FOLDERS), 'Location', 'northeast'); %[output:13941458]

%% Save
exportgraphics(gca, fullfile(out_folder, "power.svg"), 'ContentType', 'vector'); %[output:13941458]
savefig(gcf, fullfile(out_folder, "power.fig"));
%%
%[text] ## Peak Frequencies
figure %[output:2354aeb8]
Process.format_plot("", "Separation, $\Delta z/l$", "Propeller Speed, Hz"); %[output:2354aeb8]

xlim([0 9]); %[output:2354aeb8]
set(gcf, 'Position', [100 100 750 750]); %[output:2354aeb8]

handles = gobjects(length(FOLDERS), 1);

for k = 1:length(FOLDERS)
    folder = FOLDERS{k};
    load(fullfile(BASE_FOLDER, folder, 'processed_data.mat'), 'results');
    SDS = results.(name).SD / (Config.L / 1000);
    transducer = table2array(results.("Transducer RPS")(:, 2:end));

    plot(SDS, median(transducer, 2), ".-", 'Color', colors(k, :), 'LineWidth', 1.5, 'MarkerSize', 15); %[output:2354aeb8]
end

legend(values(LABELS, FOLDERS), 'Location', 'northeast'); %[output:2354aeb8]

%% Save
exportgraphics(gca, fullfile(out_folder, "frequency.svg"), 'ContentType', 'vector'); %[output:2354aeb8]
savefig(gcf, fullfile(out_folder, "frequency.fig"));

